// Validate and normalize the incoming URL
const input = $input.first().json;
const body = input.body || input;

const url = (body.url || '').trim();
if (!url) {
  throw new Error('Missing required field: url');
}

// Basic URL validation using regex (URL constructor not available in sandbox)
const urlPattern = /^https?:\/\/[^\s/$.?#].[^\s]*$/i;
if (!urlPattern.test(url)) {
  throw new Error(`Invalid URL format: ${url}`);
}

// Normalize: remove trailing slash, remove fragment
let normalized = url.split('#')[0].replace(/\/+$/, '');

return [{
  json: {
    url: normalized,
    tags: body.tags || [],
    category: body.category || '',
    title: body.title || ''
  }
}];

// Validate scraped content and extract metadata
const scrapeResult = $input.first().json;
const inputData = $('Validate URL').first().json;

// Check for scrape errors (continueOnFail produces error fields)
if (scrapeResult.error || scrapeResult.code === 'SCRAPE_TIMEOUT') {
  const errMsg = scrapeResult.error || scrapeResult.message || 'Scrape failed';
  return [{
    json: {
      valid: false,
      error: `Scrape error: ${typeof errMsg === 'object' ? JSON.stringify(errMsg) : errMsg}`,
      url: inputData.url
    }
  }];
}

// Extract markdown content
const data = scrapeResult.data || scrapeResult;
const markdown = data.markdown || '';
const metadata = data.metadata || {};

if (markdown.length < 100) {
  return [{
    json: {
      valid: false,
      error: `Content too short (${markdown.length} chars). Minimum 100 chars required.`,
      url: inputData.url
    }
  }];
}

// Use provided title, or extract from metadata, or from content
let title = inputData.title;
if (!title) {
  title = metadata.title || metadata.ogTitle || '';
}
if (!title) {
  // Extract first heading from markdown
  const headingMatch = markdown.match(/^#\s+(.+)$/m);
  if (headingMatch) {
    title = headingMatch[1].trim();
  }
}
if (!title) {
  title = 'Untitled';
}

// Generate filename from title
const filename = title
  .replace(/[^a-zA-Z0-9\u4e00-\u9fff\s-]/g, '')
  .replace(/\s+/g, '-')
  .substring(0, 80) + '.md';

// Extract keywords from title for tag matching
const keywords = title
  .replace(/[^a-zA-Z0-9\u4e00-\u9fff\s]/g, ' ')
  .split(/\s+/)
  .filter(w => w.length > 1)
  .slice(0, 10);

return [{
  json: {
    valid: true,
    content: markdown,
    title: title,
    filename: filename,
    url: inputData.url,
    tags: inputData.tags,
    category: inputData.category,
    keywords: keywords
  }
}];

// Merge LLM tags, matched tags, and user-provided tags
const llmRaw = $('LLM Classify').first().json;
// Handle both { data: { tags, dataset_id } } and { tags, dataset_id } formats
const llmResult = llmRaw.data || llmRaw;
const matchResult = $('Match Tags').first().json;
const contentData = $('Validate Content').first().json;

// Extract LLM tags (empty if LLM failed)
const llmTags = (llmResult.tags || []).filter(t => t);
const llmDatasetId = llmResult.dataset_id || '';

// Extract matched tags
const matchedTags = (matchResult.tags || matchResult.matched || []).map(t => typeof t === 'string' ? t : t.name || t.tag || '');
const userTags = contentData.tags || [];

// Combine and deduplicate: LLM tags + user tags + matched tags
const allTags = [...new Set([...llmTags, ...userTags, ...matchedTags])].filter(t => t);

return [{
  json: {
    content: contentData.content,
    filename: contentData.filename,
    title: contentData.title,
    url: contentData.url,
    tags: allTags,
    category: contentData.category,
    dataset_id: llmDatasetId
  }
}];

// Build response: handle upload success or failure
const uploadResult = $input.first().json;
const mergeData = $('Merge Tags').first().json;

if (uploadResult.error) {
  const errMsg = typeof uploadResult.error === 'object'
    ? (uploadResult.error.message || JSON.stringify(uploadResult.error))
    : String(uploadResult.error);
  return [{
    json: {
      success: false,
      status: 'upload_failed',
      error: errMsg,
      title: mergeData.title,
      url: mergeData.url
    }
  }];
}

return [{
  json: {
    success: true,
    status: 'ingested',
    title: mergeData.title,
    url: mergeData.url,
    tags: mergeData.tags,
    category: mergeData.category,
    uploadResult: uploadResult
  }
}];
